const DIAGNOSE_SYSTEM_PROMPT = `You are a container deployment diagnostician for the CKO AI Sandbox platform. This platform runs user containers on AWS ECS Fargate behind an ALB, with CloudWatch logging, optional EFS storage, and optional Bedrock access.

Platform specifics:
- Containers MUST listen on port 3000 and respond to HTTP GET / with a 2xx status
- The ALB health check hits port 3000 on path / every 10s (2 consecutive failures = unhealthy, 30s grace period)
- Images are built via CodeBuild from user-uploaded source or Dockerfiles, pushed to ECR
- CodeBuild has NO public internet — npm/pip use AWS CodeArtifact, Docker Hub uses ECR pull-through cache
- ECS services use deployment circuit breakers with automatic rollback
- Containers run in private subnets with ALB routing via host-header rules
- Container schedules may stop/start containers outside business hours
- Secrets are injected via SSM Parameter Store into the ECS task definition
- Storage is via EFS access points mounted at a configurable path (default /data)
- Default resources: 1 vCPU (1024 units), 2 GB memory (2048 MB)

Analyse the diagnostic data and respond with:

1. **Root Cause** — A concise 1-2 sentence summary of what is wrong.
2. **Evidence** — The specific data points (log lines, exit codes, events) that led to this conclusion.
3. **Recommended Fix** — Concrete steps the user should take to resolve the issue.

Common failure patterns:
- Health check failure (app starts but listens on wrong port, or doesn't serve / path)
- Application crash (non-zero exit code, unhandled exception, missing dependency)
- OOM kill (exit code 137, OutOfMemoryError in logs)
- Image pull failure (ECR auth issue, image not found)
- Build failure (syntax errors, missing deps, Dockerfile issues, no internet for external registries)
- EFS mount failure (storage misconfiguration)
- Scheduled stop (container stopped by schedule — not an error)

Be concise and direct. Do not speculate beyond what the data shows.`;

async function diagnoseSite(siteName) {
  const site = await getSite(siteName);
  if (!(site.site_type || "").includes("container")) {
    throw Object.assign(new Error("Site does not have container component"), { statusCode: 400 });
  }
  if (!site.container_status || site.container_status === "not_configured") {
    throw Object.assign(new Error("Container has not been deployed yet"), { statusCode: 400 });
  }

  const diagnosticData = {
    site_metadata: {
      site_name: site.site_name,
      container_status: site.container_status,
      container_image: site.container_image || null,
      storage_enabled: site.storage_enabled || false,
      bedrock_enabled: site.bedrock_enabled || false,
      secrets_enabled: site.secrets_enabled || false,
      container_schedule: site.container_schedule || null,
    },
    ecs_status: null,
    stopped_tasks: [],
    service_events: [],
    deployments: [],
    container_logs: [],
    build_info: null,
    data_sources: { ecs_status: false, container_logs: false, build_info: false },
  };

  const [ecsResult, logsResult] = await Promise.allSettled([
    lambda.send(new InvokeCommand({
      FunctionName: MCP_API_FUNCTION_NAME,
      InvocationType: "RequestResponse",
      Payload: JSON.stringify({ httpMethod: "GET", path: `/api/sites/${siteName}` }),
    })),
    lambda.send(new InvokeCommand({
      FunctionName: MCP_API_FUNCTION_NAME,
      InvocationType: "RequestResponse",
      Payload: JSON.stringify({
        httpMethod: "GET",
        path: `/api/sites/${siteName}/logs`,
        queryStringParameters: { startTime: String(Date.now() - 3600000) },
      }),
    })),
  ]);

  if (ecsResult.status === "fulfilled") {
    try {
      const resp = JSON.parse(new TextDecoder().decode(ecsResult.value.Payload));
      if (resp.statusCode === 200) {
        const data = JSON.parse(resp.body);
        diagnosticData.ecs_status = {
          ecs_status: data.ecs_status,
          running_count: data.running_count,
          desired_count: data.desired_count,
          pending_count: data.pending_count,
          deployment_status: data.deployment_status,
          deployment_failed: data.deployment_failed,
        };
        diagnosticData.stopped_tasks = data.stopped_tasks || [];
        diagnosticData.service_events = (data.service_events || []).slice(0, 10);
        diagnosticData.deployments = (data.deployments || []).slice(0, 3);
        diagnosticData.data_sources.ecs_status = true;
      }
    } catch { /* best-effort */ }
  }

  if (logsResult.status === "fulfilled") {
    try {
      const resp = JSON.parse(new TextDecoder().decode(logsResult.value.Payload));
      if (resp.statusCode === 200) {
        const data = JSON.parse(resp.body);
        diagnosticData.container_logs = (data.events || []).slice(-100);
        diagnosticData.data_sources.container_logs = true;
      }
    } catch { /* best-effort */ }
  }

  if (site.container_status === "build_failed" && site.container_build_id) {
    try {
      const { builds } = await codebuild.send(new BatchGetBuildsCommand({ ids: [site.container_build_id] }));
      if (builds && builds[0]) {
        const b = builds[0];
        diagnosticData.build_info = {
          status: b.buildStatus,
          phases: (b.phases || []).map(p => ({
            name: p.phaseType,
            status: p.phaseStatus,
            duration: p.durationInSeconds,
            errors: (p.contexts || []).filter(c => c.statusCode).map(c => `${c.statusCode}: ${c.message}`),
          })),
        };
        if (b.buildStatus === "FAILED" && b.logs?.groupName && b.logs?.streamName) {
          const { events = [] } = await cwlogs.send(new GetLogEventsCommand({
            logGroupName: b.logs.groupName,
            logStreamName: b.logs.streamName,
            startFromHead: false,
            limit: 50,
          }));
          diagnosticData.build_info.build_logs = events.map(e => e.message).join("");
        }
        diagnosticData.data_sources.build_info = true;
      }
    } catch { /* best-effort */ }
  }

  const logLines = diagnosticData.container_logs.map(e => e.message).join("\n");
  const userMessage = [
    `Diagnose why the container "${siteName}" is failing.\n`,
    `## Site Configuration\n${JSON.stringify(diagnosticData.site_metadata, null, 2)}\n`,
    diagnosticData.data_sources.ecs_status
      ? `## ECS Service Status\n${JSON.stringify(diagnosticData.ecs_status, null, 2)}\n`
      : "## ECS Service Status\nUnavailable\n",
    diagnosticData.stopped_tasks.length > 0
      ? `## Stopped Tasks\n${JSON.stringify(diagnosticData.stopped_tasks, null, 2)}\n`
      : "",
    diagnosticData.deployments.length > 0
      ? `## Deployments\n${JSON.stringify(diagnosticData.deployments, null, 2)}\n`
      : "",
    diagnosticData.service_events.length > 0
      ? `## Service Events (most recent first)\n${diagnosticData.service_events.map(e => e.message).join("\n")}\n`
      : "",
    logLines
      ? `## Container Logs (last ${diagnosticData.container_logs.length} events)\n${logLines}\n`
      : "## Container Logs\nNo logs available\n",
    diagnosticData.data_sources.build_info
      ? `## Build Information\n${JSON.stringify(diagnosticData.build_info, null, 2)}\n`
      : "",
  ].join("\n");

  try {
    const response = await bedrock.send(new BedrockInvokeModelCommand({
      modelId: BEDROCK_MODEL_ID || "eu.anthropic.claude-sonnet-4-20250514",
      contentType: "application/json",
      accept: "application/json",
      body: JSON.stringify({
        anthropic_version: "bedrock-2023-05-31",
        max_tokens: 1024,
        system: DIAGNOSE_SYSTEM_PROMPT,
        messages: [{ role: "user", content: userMessage }],
      }),
    }));
    const result = JSON.parse(new TextDecoder().decode(response.body));
    const diagnosis = result.content?.[0]?.text;
    if (!diagnosis) {
      throw new Error("Empty response from AI model");
    }
    return {
      site_name: siteName,
      diagnosis,
      diagnosed_at: new Date().toISOString(),
      data_sources: diagnosticData.data_sources,
    };
  } catch (err) {
    if (err.statusCode) throw err;
    console.error("Bedrock diagnosis failed:", err);
    throw Object.assign(new Error("AI diagnosis unavailable — please try again"), { statusCode: 502 });
  }
}

