function renderMarkdown(md) {
  return esc(md)
    .replace(/^### (.+)$/gm, '<h4>$1</h4>')
    .replace(/^## (.+)$/gm, '<h3>$1</h3>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/\n\n/g, '<br><br>')
    .replace(/\n/g, '<br>');
}

async function showDiagnoseModal(siteName) {
  const existing = document.getElementById("diagnoseModal");
  if (existing) existing.remove();

  const overlay = document.createElement("div");
  overlay.className = "modal-overlay";
  overlay.id = "diagnoseModal";
  overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
  overlay.innerHTML = `
    <div class="modal" style="max-width:640px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:1rem">
        <h3 style="margin:0">AI Diagnosis</h3>
        <button class="btn btn-ghost btn-sm" onclick="document.getElementById('diagnoseModal').remove()">Close</button>
      </div>
      <div id="diagnoseContent">
        <div class="loading-state"><div class="spinner"></div><p>Analysing container...</p></div>
      </div>
    </div>
  `;
  document.body.appendChild(overlay);

  try {
    const result = await api("POST", `/sites/${siteName}/container/diagnose`);
    const content = document.getElementById("diagnoseContent");
    if (!content) return;
    content.innerHTML = `
      <div class="diagnosis-result">${renderMarkdown(result.diagnosis)}</div>
