input.old_string:
# ── Public ACM certificate ──────────────────────────────────────────────────
resource "aws_acm_certificate" "mcp" {
  domain_name       = local.mcp_domain_name
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route53_record" "mcp_cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.mcp.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  zone_id = data.aws_route53_zone.public.zone_id
  name    = each.value.name
  type    = each.value.type
  ttl     = 60
  records = [each.value.record]
}

resource "aws_acm_certificate_validation" "mcp" {
  certificate_arn         = aws_acm_certificate.mcp.arn
  validation_record_fqdns = [for record in aws_route53_record.mcp_cert_validation : record.fqdn]
}

# ── Custom domain with public cert ──────────────────────────────────────────
resource "aws_api_gateway_domain_name" "mcp" {
  domain_name              = local.mcp_domain_name
  regional_certificate_arn = aws_acm_certificate_validation.mcp.certificate_arn

  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

resource "aws_api_gateway_base_path_mapping" "mcp" {
  api_id      = aws_api_gateway_rest_api.mcp.id
  stage_name  = aws_api_gateway_stage.mcp.stage_name
  domain_name = aws_api_gateway_domain_name.mcp.domain_name
}

# ── DNS record ──────────────────────────────────────────────────────────────
resource "aws_route53_record" "mcp" {
  zone_id = data.aws_route53_zone.public.zone_id
  name    = local.mcp_domain_name
  type    = "A"

  alias {
    name                   = aws_api_gateway_domain_name.mcp.regional_domain_name
    zone_id                = aws_api_gateway_domain_name.mcp.regional_zone_id
    evaluate_target_health = false
  }
}

